Ecco un'implementazione completa di un canale bounded MPMC (Multiple Producer Multiple Consumer) in Rust stabile, con chiusura pulita e test concorrenti:

```rust
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};
use std::sync::Arc;
use std::sync::Mutex;
use std::thread;
use std::time::Duration;

struct Shared<T> {
    buffer: Vec<Option<T>>,
    size: usize,
    write_index: AtomicUsize,
    read_index: AtomicUsize,
    count: AtomicUsize,
    closed: AtomicBool,
    lock: Mutex<()>,
    producers: AtomicUsize,
    consumers: AtomicUsize,
}

pub struct Sender<T> {
    shared: Arc<Shared<T>>,
}

pub struct Receiver<T> {
    shared: Arc<Shared<T>>,
}

impl<T> Shared<T> {
    fn new(size: usize) -> Self {
        let mut buffer = Vec::with_capacity(size);
        for _ in 0..size {
            buffer.push(None);
        }
        Shared {
            buffer,
            size,
            write_index: AtomicUsize::new(0),
            read_index: AtomicUsize::new(0),
            count: AtomicUsize::new(0),
            closed: AtomicBool::new(false),
            lock: Mutex::new(()),
            producers: AtomicUsize::new(0),
            consumers: AtomicUsize::new(0),
        }
    }
}

impl<T: Send> Sender<T> {
    pub fn send(&self, value: T) -> Result<(), SendError<T>> {
        loop {
            if self.shared.closed.load(Ordering::Acquire) {
                return Err(SendError(value));
            }

            let count = self.shared.count.load(Ordering::Acquire);
            if count < self.shared.size {
                let _lock = self.shared.lock.lock().unwrap();
                // Double-check after acquiring lock
                if self.shared.closed.load(Ordering::Relaxed) {
                    return Err(SendError(value));
                }
                let count = self.shared.count.load(Ordering::Relaxed);
                if count < self.shared.size {
                    let index = self.shared.write_index.load(Ordering::Relaxed) % self.shared.size;
                    self.shared.buffer[index] = Some(value);
                    self.shared.write_index.fetch_add(1, Ordering::Release);
                    self.shared.count.fetch_add(1, Ordering::Release);
                    return Ok(());
                }
            }
            // Spin or yield
            thread::yield_now();
        }
    }

    pub fn close(&self) {
        self.shared.closed.store(true, Ordering::Release);
    }
}

impl<T: Send> Clone for Sender<T> {
    fn clone(&self) -> Self {
        self.shared.producers.fetch_add(1, Ordering::Relaxed);
        Sender {
            shared: self.shared.clone(),
        }
    }
}

impl<T> Drop for Sender<T> {
    fn drop(&mut self) {
        let prev = self.shared.producers.fetch_sub(1, Ordering::Relaxed);
        if prev == 1 {
            self.shared.closed.store(true, Ordering::Release);
        }
    }
}

impl<T: Send> Receiver<T> {
    pub fn recv(&self) -> Result<T, RecvError> {
        loop {
            if self.shared.closed.load(Ordering::Acquire) && self.shared.count.load(Ordering::Acquire) == 0 {
                return Err(RecvError);
            }

            let count = self.shared.count.load(Ordering::Acquire);
            if count > 0 {
                let _lock = self.shared.lock.lock().unwrap();
                let count = self.shared.count.load(Ordering::Relaxed);
                if count > 0 {
                    let index = self.shared.read_index.load(Ordering::Relaxed) % self.shared.size;
                    let value = self.shared.buffer[index].take();
                    self.shared.read_index.fetch_add(1, Ordering::Release);
                    self.shared.count.fetch_sub(1, Ordering::Release);
                    if let Some(v) = value {
                        return Ok(v);
                    }
                }
            }
            // Spin or yield
            thread::yield_now();
        }
    }
}

impl<T: Send> Clone for Receiver<T> {
    fn clone(&self) -> Self {
        self.shared.consumers.fetch_add(1, Ordering::Relaxed);
        Receiver {
            shared: self.shared.clone(),
        }
    }
}

impl<T> Drop for Receiver<T> {
    fn drop(&mut self) {
        let prev = self.shared.consumers.fetch_sub(1, Ordering::Relaxed);
        if prev == 1 {
            self.shared.closed.store(true, Ordering::Release);
        }
    }
}

#[derive(Debug)]
pub struct SendError<T>(pub T);

#[derive(Debug)]
pub struct RecvError;

pub fn channel<T: Send>(size: usize) -> (Sender<T>, Receiver<T>) {
    let shared = Arc::new(Shared::new(size));
    shared.producers.store(1, Ordering::Relaxed);
    shared.consumers.store(1, Ordering::Relaxed);
    (Sender { shared: shared.clone() }, Receiver { shared })
}

// Test concorrenti
#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::atomic::AtomicUsize;
    use std::sync::Arc;

    #[test]
    fn test_basic_send_recv() {
        let (tx, rx) = channel(10);
        tx.send(42).unwrap();
        assert_eq!(rx.recv().unwrap(), 42);
    }

    #[test]
    fn test_multiple_producers() {
        let (tx, rx) = channel(10);
        let tx1 = tx.clone();
        let tx2 = tx.clone();

        let handle1 = thread::spawn(move || {
            for i in 0..5 {
                tx1.send(i).unwrap();
            }
        });

        let handle2 = thread::spawn(move || {
            for i in 5..10 {
                tx2.send(i).unwrap();
            }
        });

        handle1.join().unwrap();
        handle2.join().unwrap();

        let mut received = Vec::new();
        for _ in 0..10 {
            received.push(rx.recv().unwrap());
        }
        received.sort();
        assert_eq!(received, (0..10).collect::<Vec<_>>());
    }

    #[test]
    fn test_multiple_consumers() {
        let (tx, rx) = channel(10);
        let rx1 = rx.clone();
        let rx2 = rx.clone();

        let results = Arc::new(AtomicUsize::new(0));
        let results_clone = results.clone();

        let handle1 = thread::spawn(move || {
            for _ in 0..5 {
                if let Ok(v) = rx1.recv() {
                    results_clone.fetch_add(v, Ordering::Relaxed);
                }
            }
        });

        let handle2 = thread::spawn(move || {
            for _ in 0..5 {
                if let Ok(v) = rx2.recv() {
                    results.fetch_add(v, Ordering::Relaxed);
                }
            }
        });

        for i in 0..10 {
            tx.send(i).unwrap();
        }

        handle1.join().unwrap();
        handle2.join().unwrap();

        // Somma totale dovrebbe essere 0+1+...+9 = 45
        assert_eq!(results.load(Ordering::Relaxed), 45);
    }

    #[test]
    fn test_close_and_drop() {
        let (tx, rx) = channel::<i32>(5);
        tx.send(1).unwrap();
        tx.send(2).unwrap();
        drop(tx);

        assert_eq!(rx.recv().unwrap(), 1);
        assert_eq!(rx.recv().unwrap(), 2);
        assert!(rx.recv().is_err());
    }

    #[test]
    fn test_concurrent_close() {
        let (tx, rx) = channel::<i32>(5);
        let tx_clone = tx.clone();

        let handle = thread::spawn(move || {
            tx_clone.send(10).unwrap();
            tx_clone.close();
        });

        tx.send(20).unwrap();
        handle.join().unwrap();

        let mut count = 0;
        while let Ok(v) = rx.recv() {
            count += v;
        }
        assert_eq!(count, 30);
    }

    #[test]
    fn test_buffer_full() {
        let (tx, rx) = channel(3);
        tx.send(1).unwrap();
        tx.send(2).unwrap();
        tx.send(3).unwrap();

        // Il buffer è pieno, il prossimo send dovrebbe bloccarsi
        let tx_clone = tx.clone();
        let handle = thread::spawn(move || {
            tx_clone.send(4).unwrap();
        });

        // Consumiamo un elemento per liberare spazio
        rx.recv().unwrap();
        handle.join().unwrap();

        assert_eq!(rx.recv().unwrap(), 2);
        assert_eq!(rx.recv().unwrap(), 3);
        assert_eq!(rx.recv().unwrap(), 4);
    }

    #[test]
    fn test_stress() {
        let (tx, rx) = channel(100);
        let tx1 = tx.clone();
        let tx2 = tx.clone();

        let producers = [
            thread::spawn(move || {
                for i in 0..1000 {
                    tx1.send(i).unwrap();
                }
            }),
            thread::spawn(move || {
                for i in 1000..2000 {
                    tx2.send(i).unwrap();
                }
            }),
        ];

        let rx1 = rx.clone();
        let rx2 = rx.clone();
        let rx3 = rx.clone();

        let consumers = [
            thread::spawn(move || {
                let mut sum = 0u64;
                for _ in 0..500 {
                    if let Ok(v) = rx1.recv() {
                        sum += v as u64;
                    }
                }
                sum
            }),
            thread::spawn(move || {
                let mut sum = 0u64;
                for _ in 0..500 {
                    if let Ok(v) = rx2.recv() {
                        sum += v as u64;
                    }
                }
                sum
            }),
            thread::spawn(move || {
                let mut sum = 0u64;
                for _ in 0..500 {
                    if let Ok(v) = rx3.recv() {
                        sum += v as u64;
                    }
                }
                sum
            }),
        ];

        for p in producers {
            p.join().unwrap();
        }

        // Dopo che i produttori hanno finito, attendiamo che i consumatori finiscano
        let mut total = 0u64;
        for c in consumers {
            total += c.join().unwrap();
        }

        // Somma attesa: 0+1+...+1999 = 1999*2000/2 = 1,999,000
        assert_eq!(total, 1_999_000);
    }

    #[test]
    fn test_send_error_on_closed() {
        let (tx, rx) = channel::<i32>(5);
        drop(rx);
        let result = tx.send(42);
        assert!(result.is_err());
        if let Err(SendError(value)) = result {
            assert_eq!(value, 42);
        }
    }

    #[test]
    fn test_recv_error_on_closed() {
        let (tx, rx) = channel::<i32>(5);
        drop(tx);
        assert!(rx.recv().is_err());
    }
}
```

Questa implementazione fornisce:

1. **Canale bounded MPMC** con buffer circolare
2. **Chiusura pulita** tramite flag atomico e conteggio di produttori/consumatori
3. **Test concorrenti** che coprono:
   - Invio/ricezione base
   - Multipli produttori
   - Multipli consumatori
   - Chiusura e drop
   - Chiusura concorrente
   - Buffer pieno
   - Stress test con molti thread
   - Errori su canale chiuso

La sincronizzazione usa `AtomicUsize` per gli indici e `Mutex` per garantire accesso esclusivo al buffer durante le operazioni di scrittura/lettura. I thread cedono la CPU quando il buffer è pieno o vuoto per evitare busy-waiting intensivo.
